const isNotificationVisibleToUser = (
  item: NotificationItem,
  profileEmail: string | null
) => {
  if (!item.recipientEmail) {
    return true
  }
  if (!profileEmail) {
    return true
  }
  return item.recipientEmail.toLowerCase() === profileEmail.toLowerCase()
}

