const parseAnalyticsLayerKey = (key: string) => {
  const separatorIndex = key.indexOf('::')
  return {
    kind: key.slice(0, separatorIndex) as AnalyticsSeedRecord['kind'],
    category: key.slice(separatorIndex + 2),
  }
}

